fragmentShader:
// Credits: [jarble](https://www.shadertoy.com/view/NsfSRB)

uniform vec3 u_color;
uniform float u_scale;//units:%
uniform float u_horizontal;//units:%
uniform float u_vertical;//units:%
uniform int u_intensity;//min:1,max:4


void main(){

    float scale = 100.;
    int intensity = (2 + u_intensity);
    intensity *= intensity;
    vec2 coord = ((1.001-u_scale)*100.)*scale*(gl_FragCoord.xy + vec2(1.0,0.0));

    coord.x *= (1.001 - u_horizontal);
    coord.y *= (1.001 - u_vertical);

    // Heart of color selection.
    int val = ((int(coord.x) & int(coord.y)) % 3);
    float result = 0.0;
    vec3 col = vec3(0.0);
    vec3 col_prev;
    for(int i = 0; i < intensity; i++){
        col_prev = col;
        coord.y += (4.0+result);
        coord = coord.yx/(3.0);
        result = ((result + float(val = ((int(coord.x) | int(coord.y)) % (3+val))))/(2.0));
        col.x = (result+col.z)/2.0;
        col = (fract((col.yzx))+col_prev)/2.0;
    }
    // Output.
    gl_FragColor = vec4(u_color,col);
}

